my result = List();
my softpanel_rohrlist = GetComponentListOfType('rohr750');
softpanel_rohrlist = FilterList(softpanel_rohrlist, 'r', `not (ConnectedDockCount(r, 'rohr_2_magnet') eq 2);`);
for (my rohr: softpanel_rohrlist) {
	my s1 = DockGetConnectedDock(Dock(rohr, 'rohr_2_magnet', 1));
	my s2 = DockGetConnectedDock(Dock(rohr, 'rohr_2_magnet', 2));
	//Message(Abs(GetDOFValue2(s1) + GetDOFValue2(s2)));
	if (Abs(GetDOFValue2(s1) + GetDOFValue2(s2)) gt 7) {
		ListAdd(result, DockGetPart(s1));
		ListAdd(result, DockGetPart(s2));
	}
}

return result;


	my volumes = GetVolumeList();
