conflict.conflictexpression:
  	my result = List();

  	my bl = GetComponentListOfType('normalblech');
	bl = FilterList(bl, 'b', `not (ConnectedDockCount(b, 'blech2rohr') gt 0 and ConnectedDockCount(b, 'blech2rohr') lt 4);`);

	result = bl;

  	my result = List();

  	for (my sp: ChildrenListOfTypeDeep(Forest('mainstructure'), 'as_soft_panel')) {
	  	my volume = ParentOfType(sp, 'mainstructure', 'volume');

		my rohr = FindPart(ChildOfType(sp, 'co_soft_panel'), 'magnet_2_rohr',1);

		my x  = Round(PartPos(rohr)['x']);
		my y = Round(PartPos(rohr)['y']);
		my refrohre = FilterList(GetVolumeRefParts(volume), TypeFilter('ct_verbraucherRohrE'));


		if (Size(FilterList(refrohre, 'r', `not (r ne rohr and Round(PartPos(r)['x']) eq x and Round(PartPos(r)['y']) eq y);`)) eq 0) {
			ListAdd(result, volume);		
		};

	};

	result;


my result = List();
my flist = GetComponentListOfType('fraesrohr_doppelseitig');
for (my f: flist) {
	my x = Round(PartPos(f)['x']);
	my z = Round(PartPos(f)['z']);
	my bl = GetComponentListOfType('normalblech');
	my blist = List();

	for (my b: bl) {
		my rp = RelativePartPos(b, f);
		my trans = InvertTransformation(Transformation(rp, PartRot(b)));
		if (Round(PartPos(b)['z']) eq z and Abs(trans['transx']) lt 25) {
			ListAdd(blist, b);
		}
	}

	if (Size(blist) gt 2) {
		ListExtend(result, blist);
	}


}


return result;

