my conflicts = List(); 
my roste = GetComponentListOfType('rost');
my rohr = null;
for (my rost : roste) {
  for (my index : List(1,2,3,4)) {
    rohr = FindPart(rost,'rost2rohr',index);
    if (rohr) {
      if (Feature(rohr,'f_rohrtyp') eq 'rohr-verbraucher'){
        conflicts = ListAdd(conflicts, rost);
        break; /* pro Rohr nur ein Konflikt */
      }
    }
  }
}
return conflicts;

