	  my rohr100list = GetComponentListOfType('rohr100');
	  my result = List();
	  for (my r: rohr100list) {
	  	my a = FindPart(r, 'rohr2kugel',1);
	  	my b = FindPart(r, 'rohr2kugel',2);

	  	if (a and b) {

	  		my f_a = Feature(a, 'f_stromkreis');
	  		my f_b = Feature(b, 'f_stromkreis');

  	  		Feature(a, 'f_kugelLeitend') and Feature(b, 'f_kugelLeitend') and StrLen(f_b) and f_a ne f_b ? ListAdd(result, r) : null;
	  	};
	  }; 	

	  return result;

my result = List();
 my schloss_c_list = FilterList(GetComponentListOfType('schlossgriff'), 'p', `not (Feature(p, 'Schliessung') ~ 'schloss_c');`);
 for (my schloss: schloss_c_list) {
   my klapptuer = ParentOfType(schloss, 'mainstructure', 'klapptuerset');
 	my volume =  klapptuer ? ParentOfType(schloss, 'mainstructure', 'normal_volume') : null; 
 	if (volume) {
 		my hallerfuss_list = FilterList(GetVolumeRefParts(volume), 'p', `not (IsSubTypeOf(p, 'fuesse'));`);
 		if (Size(hallerfuss_list)) {
 			ListAdd(result, klapptuer);
 		};
 	};
 };

 return result;

if(not VarDefined('_articles')){
	return List();
}
my articles = FilterList(_articles, 'ar', `ar['type'] eq 'ar_qs_article';`);
my table = CompressTable(CopyTable(articles), 'groupid', 'weight');
my components = GetComponentListOfType('ct_haller_shelf_component');
components = FilterList(components, 'c', ` (IsSubTypeOf(c, 'ct_soft_panel'));`); 
my heavy_list = List();
my heavy_volume_list = List();
for(my group: table){
	if(group['weight'] gt 80){
		my group_components = FilterList(components, 'element', `not (Feature(element,'_PXi_permanent_group_id') eq group['groupid'] ) ;`);
		my mounted_group_components = FilterList(components, 'element', `not (Feature(element,'_PXi_permanent_group_id') eq group['groupid'] and Feature(element,'Mounted') eq 'true') ;`);
		if(Size(mounted_group_components) eq Size(group_components) ){
			heavy_list = JoinList(heavy_list, FilterList(components, 'element', `not (Feature(element,'_PXi_permanent_group_id') eq group['groupid'] and Feature(element,'Mounted') eq 'true') ;`));
			my group_volumes = call getAllVolumesOfConnectionId(group_components[0]);
			heavy_volume_list = JoinList(heavy_volume_list, group_volumes);
		}
	}	
}
return heavy_volume_list;
